export default function TourModal({ open, onClose }) {
  if (!open) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      <div className="absolute inset-0 bg-black/40" onClick={onClose} />
      <div className="relative bg-white w-full max-w-md rounded-2xl p-6 shadow-2xl">
        <div className="text-xl font-semibold text-gray-900">Book a tour</div>
        <p className="text-sm text-gray-600 mt-1">Share your details and we’ll confirm your visit.</p>
        <form className="mt-4 space-y-3" onSubmit={(e) => { e.preventDefault(); onClose(); }}>
          <input className="w-full h-11 px-3 rounded-lg border border-gray-200" placeholder="Full name" />
          <input className="w-full h-11 px-3 rounded-lg border border-gray-200" placeholder="Email" />
          <input className="w-full h-11 px-3 rounded-lg border border-gray-200" placeholder="Phone" />
          <input className="w-full h-11 px-3 rounded-lg border border-gray-200" type="date" />
          <button className="w-full h-11 rounded-lg bg-brand-600 text-white font-semibold hover:bg-brand-700">Request tour</button>
        </form>
      </div>
    </div>
  );
}
